import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { PieChart } from '@mui/x-charts';
import response from './response.json';

interface CurrentMilestone {
  title: string;
  dueDate: string;
  progress: number;
}

interface UpcomingDeadline {
  title: string;
  deadline: string;
}

interface MilestoneProgress {
  name: string;
  completed: boolean;
}

interface MilestoneData {
  currentMilestone: CurrentMilestone;
  upcomingDeadlines: UpcomingDeadline[];
  milestoneProgress: MilestoneProgress[];
}

export default function Widget() {
  const milestoneData = response.data as MilestoneData;
  const { currentMilestone, upcomingDeadlines, milestoneProgress } = milestoneData;

  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#1E1E1E' }} elevation={3}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#00FF00', mb: 1 }}>
              {currentMilestone.title}
            </Typography>
            <Typography variant="body2" sx={{ color: '#FFFFFF' }}>
              Due Date: {new Date(currentMilestone.dueDate).toLocaleDateString()}
            </Typography>
            <Box sx={{ width: '100%', height: 150, mt: 2 }}>
              <PieChart
                data={[
                  { id: 'completed', value: currentMilestone.progress, color: '#00FF00' },
                  { id: 'remaining', value: 100 - currentMilestone.progress, color: '#FF00FF' }
                ]}
                radius={50}
                innerRadius={30}
                margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
              />
            </Box>
          </Box>

          <Box>
            <Typography variant="body2" sx={{ color: '#FFFFFF', mb: 1 }}>
              Upcoming Deadlines
            </Typography>
            <Stack spacing={0.5}>
              {upcomingDeadlines.map((deadline, index) => (
                <Chip
                  key={index}
                  label={`${deadline.title} - ${new Date(deadline.deadline).toLocaleDateString()}`}
                  sx={{ fontSize: '11px', color: '#000', bgcolor: '#00FF00', mb: 0.5 }}
                />
              ))}
            </Stack>
          </Box>

          <Box>
            <Typography variant="body2" sx={{ color: '#FFFFFF', mb: 1 }}>
              Milestone Progress
            </Typography>
            <Stack spacing={0.5}>
              {milestoneProgress.map((milestone, index) => (
                <Chip
                  key={index}
                  label={milestone.name}
                  sx={{
                    fontSize: '11px',
                    color: milestone.completed ? '#000' : '#FFF',
                    bgcolor: milestone.completed ? '#00FF00' : '#FF00FF',
                    mb: 0.5
                  }}
                />
              ))}
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
